  ('elementary-8b44517b-moex-00877', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '下列何者非屬視為職業傷害之情形？', '["被保險人於工作時間中基於生理需要於如廁或飲水時發生事故而致之傷害", "被保險人上、下班，於適當時間，從日常居、住處所往返就業場所之應經途中發生事故而致之傷害", "被保險人於執行職務時，因天然災害直接發生事故導致之傷害，且其從事之業務非屬遭受天然災害之 危險性較高者", "被保險人因執行職務受動物或植物傷害"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "252bd0a98402", "answer_pdf_sha1": "3e05bf291669", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00878', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '依職業災害勞工保護法之規定，下列何種情形，雇主不得預告終止與職業災害勞工之勞動契約？', '["歇業或重大虧損，報經主管機關核定", "業務緊縮", "因天災、事變或其他不可抗力因素，致事業不能繼續經營，報經主管機關核定", "職業災害勞工經醫療終止後，經公立醫療機構認定身心障礙不堪勝任工作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "252bd0a98402", "answer_pdf_sha1": "3e05bf291669", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00879', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '適用勞工退休金條例之勞工因不能勝任工作而被解僱時，對於其適用該條例後的工作年資所計算之資遣 費，最高以發給多少個月的平均工資為限？', '["3個月", "6個月", "9個月", "12個月"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "252bd0a98402", "answer_pdf_sha1": "3e05bf291669", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00880', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '適用勞工退休金條例之勞工得請領月退休金之要件為：', '["只要勞工年滿65歲即可", "勞工年滿65歲，且工作年資滿10年以上", "只要勞工工作年資滿20年以上即可", "勞工年滿60歲，且工作年資滿15年以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "252bd0a98402", "answer_pdf_sha1": "3e05bf291669", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00881', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-df89b7fb', 'sub-elementary-8b44517b-02', NULL, 'single_choice', '勞動基準法第11條所規定之雇主得預告勞工終止勞動契約的事由不包括下列何者？', '["歇業", "轉讓", "改組", "不可抗力暫停工作在一個月以上時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:34+00:00", "source_pdf_sha1": "252bd0a98402", "answer_pdf_sha1": "3e05bf291669", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "勞工行政與勞工法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00882', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-01c5eaab', 'sub-elementary-8b44517b-05', NULL, 'single_choice', '「許多青春期訂交結盟的友誼，會使人在年事稍長之後，以互相交換陳舊回憶的方式，撫慰人們各自在生命 中遭遇到的種種創傷或失落；所謂□□□□、相忘於江湖。回憶，使回憶者當下的現實顯得不再那麼沉重， 也使逝去的現實顯得□□許多」，根據前後文意，選出□最適當者：', '["遺世獨立／悲戚", "相濡以沫／輕盈", "惶恐不安／虛幻", "劍拔弩張／深刻"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00883', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-01c5eaab', 'sub-elementary-8b44517b-05', NULL, 'single_choice', '甲：不惑之年。乙：花甲之年。丙：而立之年。丁：花信之年。 以上詞語皆與年齡有關，依年紀由小到大排列，順序是：', '["乙丙甲丁", "丙甲丁乙", "丁甲乙丙", "丁丙甲乙"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00884', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-01c5eaab', 'sub-elementary-8b44517b-05', NULL, 'single_choice', '下列有關「頭髮」的成語，何者正確？', '["「童山濯濯」形容頭髮烏黑濃密", "「擢髮難數」形容掉落的頭髮不計其數", "「櫛風沐雨」形容不顧風雨辛苦奔波", "「吐哺握髮」形容生重病的樣子"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00885', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-01c5eaab', 'sub-elementary-8b44517b-05', NULL, 'single_choice', '下列與「桃」有關成語的解釋，何者正確？', '["桃夭及時－祝賀女子出嫁", "桃李滿門－比喻禮尚往來", "桃李不言－喻贈人桃李不如贈人以言", "桃羞杏讓－比喻互相頂替或代人受過"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00886', 'elementary-8b44517b', 'elementary-8b44517b-moex-110-01c5eaab', 'sub-elementary-8b44517b-05', NULL, 'single_choice', '下列有關書函用語的說明，何者最正確？', '["寫給老師的信自稱「晚生」", "信中提到自己過世的親人應加「前」字", "信中提到他人父親，應稱「令尊」", "寫給長官的信，信封收信人名下應寫「敬啟」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:35+00:00", "source_pdf_sha1": "983a9bc5fc3b", "answer_pdf_sha1": "35b7bb1ab497", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
